import java.util.ArrayList;
import java.util.List;

class Campaign {
    private String name;
    private String platform;
    private double cost;
    private double expectedReturn;

    public Campaign(String name, String platform, double cost, double expectedReturn) {
        this.name = name;
        this.platform = platform;
        this.cost = cost;
        this.expectedReturn = expectedReturn;
    }

    public String getName() {
        return name;
    }

    public String getPlatform() {
        return platform;
    }

    public double getCost() {
        return cost;
    }

    public double getExpectedReturn() {
        return expectedReturn;
    }
}

class MarketingScheduler {
    private List<Campaign> campaigns;
    private double weeklyBudget;

    public MarketingScheduler(List<Campaign> campaigns, double weeklyBudget) {
        this.campaigns = campaigns;
        this.weeklyBudget = weeklyBudget;
    }

    public List<Campaign> optimizeSchedule() {
        int n = campaigns.size();
        int budgetInCents = (int) (weeklyBudget * 100); // Convert to cents for integer math

        // Initialize DP table
        double[][] dp = new double[n + 1][budgetInCents + 1];
        boolean[][] selected = new boolean[n + 1][budgetInCents + 1];

        // Fill DP table
        for (int i = 1; i <= n; i++) {
            Campaign campaign = campaigns.get(i - 1);
            int cost = (int) (campaign.getCost() * 100); // Convert to cents

            for (int j = 0; j <= budgetInCents; j++) {
                // Default: don't include this campaign
                dp[i][j] = dp[i - 1][j];

                // If we can afford this campaign
                if (j >= cost) {
                    double returnWithCampaign = dp[i - 1][j - cost] + campaign.getExpectedReturn();
                    if (returnWithCampaign > dp[i][j]) {
                        dp[i][j] = returnWithCampaign;
                        selected[i][j] = true;
                    }
                }
            }
        }

        // Backtrack to find selected campaigns
        List<Campaign> selectedCampaigns = new ArrayList<>();
        int i = n;
        int j = budgetInCents;

        while (i > 0) {
            if (selected[i][j]) {
                Campaign campaign = campaigns.get(i - 1);
                selectedCampaigns.add(campaign);
                j -= (int) (campaign.getCost() * 100);
            }
            i--;
        }

        return selectedCampaigns;
    }
}

public class MarketingCampaignOptimizer {
    public static void main(String[] args) {
        // Sample campaigns
        List<Campaign> campaigns = new ArrayList<>();
        campaigns.add(new Campaign("Summer Sale", "Facebook", 1000, 2500));
        campaigns.add(new Campaign("Product Launch", "Instagram", 1500, 3000));
        campaigns.add(new Campaign("Holiday Special", "Google", 800, 1800));
        campaigns.add(new Campaign("Brand Awareness", "Twitter", 500, 1000));
        campaigns.add(new Campaign("Limited Offer", "LinkedIn", 1200, 2200));

        double weeklyBudget = 3000.0;

        MarketingScheduler scheduler = new MarketingScheduler(campaigns, weeklyBudget);
        List<Campaign> optimalCampaigns = scheduler.optimizeSchedule();

        // Output results
        System.out.println("Optimal Campaign Selection:");
        double totalCost = 0;
        double totalReturn = 0;

        for (Campaign campaign : optimalCampaigns) {
            System.out.println(campaign.getName() + " (" + campaign.getPlatform() + 
                    ") - Cost: $" + campaign.getCost() + 
                    ", Expected Return: $" + campaign.getExpectedReturn());
            totalCost += campaign.getCost();
            totalReturn += campaign.getExpectedReturn();
        }

        System.out.println("\nTotal Cost: $" + totalCost);
        System.out.println("Total Expected Return: $" + totalReturn);
        System.out.println("ROI: " + String.format("%.2f", (totalReturn - totalCost) / totalCost * 100) + "%");
    }
}

#include <iostream>
#include <vector>
#include <climits>
#include <algorithm>

int maxProfit(const std::vector<int>& prices) {
    if (prices.size() <= 1) {
        return 0;
    }

    int n = prices.size();
    std::vector<int> dp(n, 0);  // dp[i] = maximum profit up to day i
    int minPrice = prices[0];   // minimum price seen so far

    for (int i = 1; i < n; i++) {
        // Update minimum price seen so far
        minPrice = std::min(minPrice, prices[i]);

        // dp[i] = max profit if we sell on day i OR max profit from previous days
        dp[i] = std::max(dp[i-1], prices[i] - minPrice);
    }

    return dp[n-1];
}

int main() {
    std::vector<int> prices;
    int price;

    std::cout << "Enter stock prices (enter non-integer to stop):\n";
    while (std::cin >> price) {
        prices.push_back(price);
    }

    int result = maxProfit(prices);
    std::cout << "Maximum profit: " << result << std::endl;

    return 0;
}

function findMaxProductivityPeriod(productivityLog) {
  let maxSum = productivityLog[0];
  let currentSum = productivityLog[0];
  let startIndex = 0;
  let endIndex = 0;
  let tempStartIndex = 0;

  for (let i = 1; i < productivityLog.length; i++) {
    if (currentSum + productivityLog[i] > productivityLog[i]) {
      currentSum += productivityLog[i];
    } else {
      currentSum = productivityLog[i];
      tempStartIndex = i;
    }

    if (currentSum > maxSum) {
      maxSum = currentSum;
      startIndex = tempStartIndex;
      endIndex = i;
    }
  }

  return {
    startDay: startIndex,
    endDay: endIndex,
    totalProductivity: maxSum
  };
}

#include <iostream>
#include <vector>
#include <unordered_map>
#include <algorithm>
#include <limits>
#include <string>

struct Location {
    int id;
    double x, y;
    double waste_amount;
};

// Calculate distance between two locations
double distance(const Location& a, const Location& b) {
    return std::sqrt((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y));
}

class WasteRouteOptimizer {
private:
    std::vector<Location> locations;
    Location depot;
    double truck_capacity;
    std::vector<std::vector<double>> distances;

    // Memoization table: key is (bitmask, current_loc), value is (min_cost, waste_collected)
    std::unordered_map<std::string, std::pair<double, double>> memo;

    // Generate a unique key for memoization
    std::string getKey(int mask, int current) {
        return std::to_string(mask) + "_" + std::to_string(current);
    }

    // DP function to find optimal route
    std::pair<double, double> findOptimalRoute(int mask, int current, double current_load) {
        // If all locations are visited, return to depot
        if (mask == (1 << locations.size()) - 1) {
            return {distances[current][0], current_load};
        }

        // Check memoization table
        std::string key = getKey(mask, current);
        if (memo.find(key) != memo.end()) {
            return memo[key];
        }

        double min_cost = std::numeric_limits<double>::max();
        double final_load = current_load;

        // Try visiting each unvisited location
        for (int next = 1; next < locations.size(); next++) {
            if (!(mask & (1 << next))) {
                // Check if adding this location exceeds truck capacity
                if (current_load + locations[next].waste_amount <= truck_capacity) {
                    int new_mask = mask | (1 << next);
                    double new_load = current_load + locations[next].waste_amount;

                    auto result = findOptimalRoute(new_mask, next, new_load);
                    double cost = distances[current][next] + result.first;

                    if (cost < min_cost) {
                        min_cost = cost;
                        final_load = result.second;
                    }
                } else {
                    // If exceeding capacity, go back to depot, empty truck, and continue
                    double return_to_depot = distances[current][0];
                    int new_mask = mask | (1 << next);
                    double new_load = locations[next].waste_amount;

                    auto result = findOptimalRoute(new_mask, next, new_load);
                    double cost = return_to_depot + distances[0][next] + result.first;

                    if (cost < min_cost) {
                        min_cost = cost;
                        final_load = result.second;
                    }
                }
            }
        }

        // Store result in memoization table
        memo[key] = {min_cost, final_load};
        return {min_cost, final_load};
    }

public:
    WasteRouteOptimizer(const std::vector<Location>& locs, const Location& dep, double capacity) 
        : locations(locs), depot(dep), truck_capacity(capacity) {

        // Insert depot at the beginning of locations
        locations.insert(locations.begin(), depot);

        // Precompute distances between all locations
        int n = locations.size();
        distances.resize(n, std::vector<double>(n, 0.0));

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                distances[i][j] = distance(locations[i], locations[j]);
            }
        }
    }

    double optimizeRoute() {
        memo.clear();
        // Start from depot (index 0) with empty truck
        auto result = findOptimalRoute(1, 0, 0.0);
        return result.first;
    }

    void printOptimalRoute() {
        // Code to reconstruct and print the optimal route
        // This would trace through the DP solution to output the sequence of locations
        std::cout << "Optimal route total distance: " << optimizeRoute() << std::endl;
    }
};

int main() {
    // Example usage
    Location depot = {0, 0.0, 0.0, 0.0}; // Depot at origin with no waste

    std::vector<Location> pickup_locations = {
        {1, 2.0, 3.0, 1.5},
        {2, 5.0, 1.0, 2.0},
        {3, 8.0, 4.0, 1.0},
        {4, 3.0, 6.0, 3.0},
        {5, 6.0, 7.0, 2.5}
    };

    double truck_capacity = 5.0;

    WasteRouteOptimizer optimizer(pickup_locations, depot, truck_capacity);
    optimizer.printOptimalRoute();

    return 0;
}

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class TextAlignment {
    private static final int INFINITY = Integer.MAX_VALUE;
    private String[] words;
    private int[] wordLengths;
    private Integer[] memo;
    private int[] breakpoints;
    private int lineWidth;
    private List<String> hyphenationPoints;

    public TextAlignment(String text, int lineWidth, List<String> hyphenationPoints) {
        this.words = text.split("\\s+");
        this.wordLengths = new int[words.length];
        for (int i = 0; i < words.length; i++) {
            wordLengths[i] = words[i].length();
        }
        this.lineWidth = lineWidth;
        this.memo = new Integer[words.length];
        this.breakpoints = new int[words.length];
        this.hyphenationPoints = hyphenationPoints;
        Arrays.fill(breakpoints, -1);
    }

    public List<String> getOptimalAlignment() {
        findMinimumCost(0);
        return constructResult();
    }

    private int findMinimumCost(int start) {
        if (start >= words.length) {
            return 0;
        }

        if (memo[start] != null) {
            return memo[start];
        }

        int cost = INFINITY;
        int lineLength = 0;

        for (int i = start; i < words.length; i++) {
            // Account for word length
            lineLength += wordLengths[i];

            // Check if word can be hyphenated
            boolean hyphenated = false;
            int hyphenatedLength = 0;
            if (i < words.length - 1 && lineLength > lineWidth) {
                for (String hyphen : hyphenationPoints) {
                    if (words[i].contains(hyphen)) {
                        String[] parts = words[i].split(hyphen);
                        hyphenatedLength = parts[0].length() + 1; // +1 for hyphen
                        if (lineLength - wordLengths[i] + hyphenatedLength <= lineWidth) {
                            hyphenated = true;
                            break;
                        }
                    }
                }
            }

            // Account for spaces between words
            if (i > start) {
                lineLength += 1; // add space
            }

            // Check if line fits within width
            if (lineLength <= lineWidth || hyphenated) {
                int remainingSpace = lineWidth - (hyphenated ? lineLength - wordLengths[i] + hyphenatedLength : lineLength);
                int lineCost = remainingSpace * remainingSpace * remainingSpace; // Cubic penalty for whitespace

                int nextCost = findMinimumCost(i + 1);
                if (nextCost != INFINITY && lineCost + nextCost < cost) {
                    cost = lineCost + nextCost;
                    breakpoints[start] = i;
                }
            }

            // If line exceeds width, stop trying with more words
            if (lineLength > lineWidth && !hyphenated) {
                break;
            }
        }

        memo[start] = cost;
        return cost;
    }

    private List<String> constructResult() {
        List<String> result = new ArrayList<>();
        int start = 0;

        while (start < words.length) {
            int end = breakpoints[start];
            if (end == -1) break;

            StringBuilder line = new StringBuilder();
            for (int i = start; i <= end; i++) {
                if (i > start) line.append(" ");

                // Check for hyphenation at end of line
                if (i == end && line.length() + words[i].length() > lineWidth) {
                    boolean hyphenated = false;
                    for (String hyphen : hyphenationPoints) {
                        if (words[i].contains(hyphen)) {
                            String[] parts = words[i].split(hyphen, 2);
                            if (line.length() + parts[0].length() + 1 <= lineWidth) {
                                line.append(parts[0]).append("-");
                                hyphenated = true;
                                break;
                            }
                        }
                    }
                    if (!hyphenated) line.append(words[i]);
                } else {
                    line.append(words[i]);
                }
            }

            result.add(line.toString());
            start = end + 1;
        }

        return result;
    }
}

#include <vector>

class SensorAnalyzer {
public:
    // Function to find maximum subarray (Kadane's algorithm)
    // Returns pair of indices (start, end) and the maximum sum
    std::pair<std::pair<int, int>, int> findPeakOperationalInterval(const std::vector<int>& readings) {
        int maxSum = readings[0];
        int currentSum = readings[0];
        int start = 0;
        int end = 0;
        int tempStart = 0;

        for (int i = 1; i < readings.size(); i++) {
            // If current element is better than continuing the previous subarray
            if (readings[i] > currentSum + readings[i]) {
                currentSum = readings[i];
                tempStart = i;
            } else {
                currentSum += readings[i];
            }

            // Update maximum sum and its indices if we found better solution
            if (currentSum > maxSum) {
                maxSum = currentSum;
                start = tempStart;
                end = i;
            }
        }

        return {{start, end}, maxSum};
    }
};

package floodevac;

import java.util.*;

public class EmergencyEvacuationPlanner {
    private final Graph elevationGraph;
    private final Map<Integer, Double> waterRiseRates;
    private final double[][] memoTable;
    private final int[][] pathPredecessor;

    public EmergencyEvacuationPlanner(Graph elevationGraph, Map<Integer, Double> waterRiseRates) {
        this.elevationGraph = elevationGraph;
        this.waterRiseRates = waterRiseRates;
        this.memoTable = new double[elevationGraph.getNodeCount()][elevationGraph.getNodeCount()];
        this.pathPredecessor = new int[elevationGraph.getNodeCount()][elevationGraph.getNodeCount()];

        // Initialize memoization table
        for (double[] row : memoTable) {
            Arrays.fill(row, Double.POSITIVE_INFINITY);
        }

        // Initialize predecessor table
        for (int[] row : pathPredecessor) {
            Arrays.fill(row, -1);
        }
    }

    public List<Integer> computeSafestPath(int source, int destination, double currentTime) {
        // Reset tables for new computation
        for (double[] row : memoTable) {
            Arrays.fill(row, Double.POSITIVE_INFINITY);
        }
        for (int[] row : pathPredecessor) {
            Arrays.fill(row, -1);
        }

        // Base case: no exposure at the destination
        memoTable[destination][0] = 0;

        // Dynamic programming approach to find minimum flood exposure
        for (int hopCount = 1; hopCount < elevationGraph.getNodeCount(); hopCount++) {
            for (int node = 0; node < elevationGraph.getNodeCount(); node++) {
                for (Edge edge : elevationGraph.getEdges(node)) {
                    int nextNode = edge.getDestination();
                    double edgeWeight = computeDynamicEdgeWeight(edge, currentTime);

                    if (memoTable[nextNode][hopCount-1] != Double.POSITIVE_INFINITY) {
                        double exposureTime = memoTable[nextNode][hopCount-1] + edgeWeight;

                        if (exposureTime < memoTable[node][hopCount]) {
                            memoTable[node][hopCount] = exposureTime;
                            pathPredecessor[node][hopCount] = nextNode;
                        }
                    }
                }
            }
        }

        // Find optimal hop count for source node
        int bestHopCount = 0;
        double minExposure = Double.POSITIVE_INFINITY;

        for (int hopCount = 0; hopCount < elevationGraph.getNodeCount(); hopCount++) {
            if (memoTable[source][hopCount] < minExposure) {
                minExposure = memoTable[source][hopCount];
                bestHopCount = hopCount;
            }
        }

        // Reconstruct path using backtracking
        return reconstructPath(source, destination, bestHopCount);
    }

    private double computeDynamicEdgeWeight(Edge edge, double currentTime) {
        double baseWeight = edge.getWeight();
        double sourceElevation = elevationGraph.getNodeElevation(edge.getSource());
        double destElevation = elevationGraph.getNodeElevation(edge.getDestination());
        double waterRiseRate = Math.max(
            waterRiseRates.getOrDefault(edge.getSource(), 0.0),
            waterRiseRates.getOrDefault(edge.getDestination(), 0.0)
        );

        // Adjust weight based on current water level and rise rate
        double waterLevel = currentTime * waterRiseRate;

        // If water level exceeds elevation, increase weight significantly
        if (waterLevel > Math.min(sourceElevation, destElevation)) {
            return baseWeight * (1 + 10 * (waterLevel - Math.min(sourceElevation, destElevation)));
        }

        return baseWeight;
    }

    private List<Integer> reconstructPath(int source, int destination, int hopCount) {
        List<Integer> path = new ArrayList<>();
        int current = source;
        path.add(current);

        while (current != destination && hopCount > 0) {
            current = pathPredecessor[current][hopCount];
            if (current == -1) break; // No valid path found
            path.add(current);
            hopCount--;
        }

        return path;
    }
}

class Graph {
    private final List<List<Edge>> adjacencyList;
    private final double[] nodeElevations;

    public Graph(int nodeCount) {
        adjacencyList = new ArrayList<>(nodeCount);
        for (int i = 0; i < nodeCount; i++) {
            adjacencyList.add(new ArrayList<>());
        }
        nodeElevations = new double[nodeCount];
    }

    public void addEdge(int source, int destination, double weight) {
        adjacencyList.get(source).add(new Edge(source, destination, weight));
    }

    public List<Edge> getEdges(int node) {
        return adjacencyList.get(node);
    }

    public int getNodeCount() {
        return adjacencyList.size();
    }

    public void setNodeElevation(int node, double elevation) {
        nodeElevations[node] = elevation;
    }

    public double getNodeElevation(int node) {
        return nodeElevations[node];
    }
}

class Edge {
    private final int source;
    private final int destination;
    private final double weight;

    public Edge(int source, int destination, double weight) {
        this.source = source;
        this.destination = destination;
        this.weight = weight;
    }

    public int getSource() {
        return source;
    }

    public int getDestination() {
        return destination;
    }

    public double getWeight() {
        return weight;
    }
}

public class Knapsack {
    public static int knapsack(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        int[][] dp = new int[n + 1][capacity + 1];

        for (int i = 1; i <= n; i++) {
            for (int w = 0; w <= capacity; w++) {
                if (weights[i-1] <= w) {
                    dp[i][w] = Math.max(values[i-1] + dp[i-1][w-weights[i-1]], dp[i-1][w]);
                } else {
                    dp[i][w] = dp[i-1][w];
                }
            }
        }

        return dp[n][capacity];
    }
}

def maximize_investment(projects, budget):
    n = len(projects)
    # Initialize DP table
    dp = [0] * (budget + 1)

    # Bottom-up DP approach
    for curr_budget in range(budget + 1):
        for cost, profit in projects:
            if cost <= curr_budget:
                dp[curr_budget] = max(dp[curr_budget], dp[curr_budget - cost] + profit)

    return dp[budget]

function maxProfit(prices) {
  if (!prices || prices.length < 2) return 0;

  let maxCurr = 0;
  let maxSoFar = 0;

  for (let i = 1; i < prices.length; i++) {
    const dailyChange = prices[i] - prices[i-1];
    maxCurr = Math.max(0, maxCurr + dailyChange);
    maxSoFar = Math.max(maxSoFar, maxCurr);
  }

  return maxSoFar;
}

import java.util.*;

public class SuffixBasedSearchEngine {
    private List<String> documents;
    private List<List<Integer>> suffixArrays;
    private Map<String, Set<Integer>> invertedIndex;

    public SuffixBasedSearchEngine(List<String> documents) {
        this.documents = documents;
        this.suffixArrays = new ArrayList<>();
        this.invertedIndex = new HashMap<>();
        buildIndex();
    }

    private void buildIndex() {
        // Build suffix arrays for each document
        for (int docId = 0; docId < documents.size(); docId++) {
            String doc = documents.get(docId).toLowerCase();
            List<Suffix> suffixes = new ArrayList<>();

            // Generate all suffixes for this document
            for (int i = 0; i < doc.length(); i++) {
                suffixes.add(new Suffix(i, doc.substring(i)));
            }

            // Sort suffixes lexicographically
            Collections.sort(suffixes);

            // Store the sorted suffix array
            List<Integer> suffixArray = new ArrayList<>();
            for (Suffix suffix : suffixes) {
                suffixArray.add(suffix.position);
            }
            suffixArrays.add(suffixArray);

            // Build inverted index for faster searching
            for (int i = 0; i < doc.length(); i++) {
                for (int j = i + 1; j <= Math.min(i + 10, doc.length()); j++) {
                    String term = doc.substring(i, j);
                    invertedIndex.computeIfAbsent(term, k -> new HashSet<>()).add(docId);
                }
            }
        }
    }

    public List<String> search(String query, int maxResults) {
        query = query.toLowerCase();
        Map<Integer, Double> relevanceScores = new HashMap<>();

        // First, filter potential documents using inverted index for optimization
        Set<Integer> candidateDocs = new HashSet<>();
        for (int i = 0; i < query.length(); i++) {
            for (int j = i + 1; j <= Math.min(i + 10, query.length()); j++) {
                String term = query.substring(i, j);
                if (invertedIndex.containsKey(term)) {
                    candidateDocs.addAll(invertedIndex.get(term));
                }
            }
        }

        // If no candidates found, return empty list
        if (candidateDocs.isEmpty()) {
            return new ArrayList<>();
        }

        // Score each candidate document
        for (int docId : candidateDocs) {
            String document = documents.get(docId).toLowerCase();
            double score = calculateRelevanceScore(query, document, suffixArrays.get(docId));
            if (score > 0) {
                relevanceScores.put(docId, score);
            }
        }

        // Sort documents by relevance score and lexicographically if tied
        List<Map.Entry<Integer, Double>> sortedEntries = new ArrayList<>(relevanceScores.entrySet());
        sortedEntries.sort((e1, e2) -> {
            int scoreComparison = Double.compare(e2.getValue(), e1.getValue());
            if (scoreComparison != 0) {
                return scoreComparison;
            }
            return documents.get(e1.getKey()).compareTo(documents.get(e2.getKey()));
        });

        // Extract top results
        List<String> results = new ArrayList<>();
        for (int i = 0; i < Math.min(maxResults, sortedEntries.size()); i++) {
            results.add(documents.get(sortedEntries.get(i).getKey()));
        }

        return results;
    }

    private double calculateRelevanceScore(String query, String document, List<Integer> suffixArray) {
        double score = 0;

        // Find longest common substrings using suffix array
        for (int i = 0; i < query.length(); i++) {
            for (int j = i + 1; j <= query.length(); j++) {
                String subQuery = query.substring(i, j);
                int matches = countMatches(subQuery, document, suffixArray);
                if (matches > 0) {
                    // Weight longer matches more heavily
                    double weight = (double) subQuery.length() / query.length();
                    score += matches * weight;
                }
            }
        }

        // Normalize score by document length (favors concise documents)
        return score / Math.sqrt(document.length());
    }

    private int countMatches(String pattern, String document, List<Integer> suffixArray) {
        // Binary search on suffix array to find matches
        int left = 0;
        int right = suffixArray.size() - 1;
        int count = 0;

        while (left <= right) {
            int mid = (left + right) / 2;
            int suffixPos = suffixArray.get(mid);

            String suffix = document.substring(suffixPos);
            int compareResult;

            if (suffix.length() >= pattern.length()) {
                compareResult = suffix.substring(0, pattern.length()).compareTo(pattern);
            } else {
                compareResult = suffix.compareTo(pattern.substring(0, suffix.length()));
                if (compareResult == 0) compareResult = -1;
            }

            if (compareResult < 0) {
                left = mid + 1;
            } else if (compareResult > 0) {
                right = mid - 1;
            } else {
                // Found a match, count all occurrences
                int first = mid;
                int last = mid;

                // Find first occurrence
                while (first > 0) {
                    int prevPos = suffixArray.get(first - 1);
                    if (prevPos + pattern.length() <= document.length() && 
                        document.substring(prevPos, prevPos + pattern.length()).equals(pattern)) {
                        first--;
                    } else {
                        break;
                    }
                }

                // Find last occurrence
                while (last < suffixArray.size() - 1) {
                    int nextPos = suffixArray.get(last + 1);
                    if (nextPos + pattern.length() <= document.length() && 
                        document.substring(nextPos, nextPos + pattern.length()).equals(pattern)) {
                        last++;
                    } else {
                        break;
                    }
                }

                count = last - first + 1;
                break;
            }
        }

        return count;
    }

    private static class Suffix implements Comparable<Suffix> {
        int position;
        String suffix;

        public Suffix(int position, String suffix) {
            this.position = position;
            this.suffix = suffix;
        }

        @Override
        public int compareTo(Suffix other) {
            return this.suffix.compareTo(other.suffix);
        }
    }

    public static void main(String[] args) {
        // Example usage
        List<String> documents = Arrays.asList(
            "Java Programming Language",
            "Python Data Science",
            "Algorithms and Data Structures",
            "Machine Learning with Python",
            "Big Data Analytics",
            "Java Virtual Machine Internals",
            "Functional Programming in Java"
        );

        SuffixBasedSearchEngine engine = new SuffixBasedSearchEngine(documents);

        List<String> queries = Arrays.asList(
            "java",
            "python",
            "data",
            "programming"
        );

        for (String query : queries) {
            System.out.println("Query: " + query);
            List<String> results = engine.search(query, 3);
            for (int i = 0; i < results.size(); i++) {
                System.out.println((i+1) + ". " + results.get(i));
            }
            System.out.println();
        }
    }
}

import os
import time
import pickle
import bisect
from typing import List, Dict, Any, Tuple, Optional, Union


class BTreeNode:
    def __init__(self, leaf=True, order=128):
        self.leaf = leaf
        self.keys = []  # Contains filenames (keys)
        self.values = []  # Contains file metadata
        self.children = []  # References to child nodes
        self.order = order  # B-Tree order (max number of children)

    def is_full(self):
        return len(self.keys) >= self.order - 1


class BTree:
    def __init__(self, order=128):
        self.root = BTreeNode(leaf=True, order=order)
        self.order = order

    def search(self, key: str) -> Optional[Dict[str, Any]]:
        """Search for a file by name and return its metadata if found."""
        return self._search(self.root, key)

    def _search(self, node: BTreeNode, key: str) -> Optional[Dict[str, Any]]:
        i = bisect.bisect_left(node.keys, key)

        # Check if key is found at this position
        if i < len(node.keys) and node.keys[i] == key:
            return node.values[i]

        # If leaf node and key not found, return None
        if node.leaf:
            return None

        # Continue search in appropriate child node
        return self._search(node.children[i], key)

    def insert(self, key: str, value: Dict[str, Any]):
        """Insert a new file entry or update an existing one."""
        # If root is full, we need to split it
        if self.root.is_full():
            new_root = BTreeNode(leaf=False, order=self.order)
            new_root.children.append(self.root)
            self._split_child(new_root, 0)
            self.root = new_root

        self._insert_non_full(self.root, key, value)

    def _insert_non_full(self, node: BTreeNode, key: str, value: Dict[str, Any]):
        i = len(node.keys) - 1

        if node.leaf:
            # Find the position to insert the key
            while i >= 0 and key < node.keys[i]:
                i -= 1
            i += 1

            # Check if key already exists (update value)
            if i > 0 and i <= len(node.keys) and node.keys[i-1] == key:
                node.values[i-1] = value
                return

            # Insert new key-value pair
            node.keys.insert(i, key)
            node.values.insert(i, value)
        else:
            # Find the child which will have the new key
            while i >= 0 and key < node.keys[i]:
                i -= 1
            i += 1

            # If the child is full, split it
            if node.children[i].is_full():
                self._split_child(node, i)
                if key > node.keys[i]:
                    i += 1

            # Recursively insert the key
            self._insert_non_full(node.children[i], key, value)

    def _split_child(self, parent: BTreeNode, index: int):
        order = self.order
        mid = order // 2 - 1

        y = parent.children[index]
        z = BTreeNode(leaf=y.leaf, order=order)

        # Move the median key to the parent
        parent.keys.insert(index, y.keys[mid])
        parent.values.insert(index, y.values[mid])
        parent.children.insert(index + 1, z)

        # Move half of y's keys and values to z
        z.keys = y.keys[mid+1:]
        z.values = y.values[mid+1:]
        y.keys = y.keys[:mid]
        y.values = y.values[:mid]

        # If y is not a leaf, move children as well
        if not y.leaf:
            z.children = y.children[mid+1:]
            y.children = y.children[:mid+1]

    def delete(self, key: str) -> bool:
        """Delete a file entry by key. Returns True if deleted, False if not found."""
        return self._delete(self.root, key)

    def _delete(self, node: BTreeNode, key: str) -> bool:
        i = bisect.bisect_left(node.keys, key)

        # Key found in this node
        if i < len(node.keys) and node.keys[i] == key:
            if node.leaf:
                # Simply remove the key-value pair
                node.keys.pop(i)
                node.values.pop(i)
                return True
            else:
                return self._delete_internal_node(node, key, i)

        # Key not found in current node
        if node.leaf:
            return False

        # Prepare child for deletion if necessary
        if len(node.children[i].keys) <= self.order // 2 - 1:
            self._fill_child(node, i)

        # If the last child has been merged, adjust the index
        if i > len(node.children) - 1:
            return self._delete(node.children[i-1], key)

        return self._delete(node.children[i], key)

    def _delete_internal_node(self, node: BTreeNode, key: str, idx: int) -> bool:
        # Case 1: If the child that precedes key has at least order/2 keys
        if len(node.children[idx].keys) >= self.order // 2:
            # Find predecessor
            pred = self._get_predecessor(node, idx)
            node.keys[idx] = pred[0]
            node.values[idx] = pred[1]
            return self._delete(node.children[idx], pred[0])

        # Case 2: If the child that follows key has at least order/2 keys
        elif len(node.children[idx+1].keys) >= self.order // 2:
            # Find successor
            succ = self._get_successor(node, idx)
            node.keys[idx] = succ[0]
            node.values[idx] = succ[1]
            return self._delete(node.children[idx+1], succ[0])

        # Case 3: Merge children
        else:
            self._merge_children(node, idx)
            return self._delete(node.children[idx], key)

    def _get_predecessor(self, node: BTreeNode, idx: int) -> Tuple[str, Dict[str, Any]]:
        curr = node.children[idx]
        while not curr.leaf:
            curr = curr.children[-1]
        return curr.keys[-1], curr.values[-1]

    def _get_successor(self, node: BTreeNode, idx: int) -> Tuple[str, Dict[str, Any]]:
        curr = node.children[idx+1]
        while not curr.leaf:
            curr = curr.children[0]
        return curr.keys[0], curr.values[0]

    def _fill_child(self, node: BTreeNode, idx: int):
        # Try to borrow from left sibling
        if idx > 0 and len(node.children[idx-1].keys) > self.order // 2 - 1:
            self._borrow_from_prev(node, idx)
        # Try to borrow from right sibling
        elif idx < len(node.children) - 1 and len(node.children[idx+1].keys) > self.order // 2 - 1:
            self._borrow_from_next(node, idx)
        # Merge with a sibling
        else:
            if idx < len(node.children) - 1:
                self._merge_children(node, idx)
            else:
                self._merge_children(node, idx-1)

    def _borrow_from_prev(self, node: BTreeNode, idx: int):
        child = node.children[idx]
        sibling = node.children[idx-1]

        # Shift all keys in child one step ahead
        child.keys.insert(0, node.keys[idx-1])
        child.values.insert(0, node.values[idx-1])

        # Move sibling's last key to parent
        node.keys[idx-1] = sibling.keys.pop()
        node.values[idx-1] = sibling.values.pop()

        # Move sibling's last child to child's first position
        if not child.leaf:
            child.children.insert(0, sibling.children.pop())

    def _borrow_from_next(self, node: BTreeNode, idx: int):
        child = node.children[idx]
        sibling = node.children[idx+1]

        # Move parent's key to child's end
        child.keys.append(node.keys[idx])
        child.values.append(node.values[idx])

        # Move sibling's first key to parent
        node.keys[idx] = sibling.keys.pop(0)
        node.values[idx] = sibling.values.pop(0)

        # Move sibling's first child to child's last position
        if not child.leaf:
            child.children.append(sibling.children.pop(0))

    def _merge_children(self, node: BTreeNode, idx: int):
        child = node.children[idx]
        sibling = node.children[idx+1]

        # Add key from parent to child
        child.keys.append(node.keys[idx])
        child.values.append(node.values[idx])

        # Copy all keys from sibling to child
        child.keys.extend(sibling.keys)
        child.values.extend(sibling.values)

        # If not leaf, copy children too
        if not child.leaf:
            child.children.extend(sibling.children)

        # Remove key from parent and remove the sibling
        node.keys.pop(idx)
        node.values.pop(idx)
        node.children.pop(idx+1)

        # If parent is the root and becomes empty, make child the new root
        if node == self.root and not node.keys:
            self.root = child


class DirectoryIndex:
    def __init__(self, storage_path="index.db", order=128):
        self.storage_path = storage_path
        self.btree = self._load_or_create_index(order)

    def _load_or_create_index(self, order) -> BTree:
        """Load existing index or create a new one."""
        if os.path.exists(self.storage_path):
            try:
                with open(self.storage_path, 'rb') as f:
                    return pickle.load(f)
            except Exception:
                return BTree(order=order)
        return BTree(order=order)

    def add_file(self, filename: str, size: int, creation_date: float = None):
        """Add or update a file in the index."""
        if creation_date is None:
            creation_date = time.time()

        metadata = {
            "size": size,
            "creation_date": creation_date,
            "last_modified": time.time()
        }

        self.btree.insert(filename, metadata)

    def get_file(self, filename: str) -> Optional[Dict[str, Any]]:
        """Retrieve file metadata by filename."""
        return self.btree.search(filename)

    def delete_file(self, filename: str) -> bool:
        """Delete a file from the index."""
        return self.btree.delete(filename)

    def persist(self):
        """Save the index to disk."""
        with open(self.storage_path, 'wb') as f:
            pickle.dump(self.btree, f)

    def close(self):
        """Persist and close the index."""
        self.persist()


# Example usage
if __name__ == "__main__":
    index = DirectoryIndex()

    # Add files
    index.add_file("document.txt", 1024)
    index.add_file("image.jpg", 5242880)

    # Lookup file
    file_info = index.get_file("document.txt")

    # Update file
    index.add_file("document.txt", 2048)  # Size updated

    # Delete file
    index.delete_file("image.jpg")

    # Save index
    index.persist()

    # Close index
    index.close()

#include <iostream>
#include <vector>
#include <string>
#include <functional>
#include <algorithm>

class Task {
private:
    std::string name;
    int priority;
    int executionTime;

public:
    Task(const std::string& taskName, int taskPriority, int taskExecutionTime)
        : name(taskName), priority(taskPriority), executionTime(taskExecutionTime) {}

    std::string getName() const { return name; }
    int getPriority() const { return priority; }
    int getExecutionTime() const { return executionTime; }
};

class TaskScheduler {
private:
    std::vector<Task> heap;

    void heapifyUp(int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && heap[parent].getPriority() < heap[index].getPriority()) {
            std::swap(heap[parent], heap[index]);
            heapifyUp(parent);
        }
    }

    void heapifyDown(int index) {
        int largest = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;

        if (left < heap.size() && heap[left].getPriority() > heap[largest].getPriority())
            largest = left;

        if (right < heap.size() && heap[right].getPriority() > heap[largest].getPriority())
            largest = right;

        if (largest != index) {
            std::swap(heap[index], heap[largest]);
            heapifyDown(largest);
        }
    }

public:
    void addTask(const Task& task) {
        heap.push_back(task);
        heapifyUp(heap.size() - 1);
    }

    Task getNextTask() {
        if (heap.empty()) {
            throw std::runtime_error("No tasks available");
        }
        return heap[0];
    }

    Task removeNextTask() {
        if (heap.empty()) {
            throw std::runtime_error("No tasks available");
        }

        Task nextTask = heap[0];
        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }

        return nextTask;
    }

    bool isEmpty() const {
        return heap.empty();
    }

    int size() const {
        return heap.size();
    }
};

int main() {
    TaskScheduler scheduler;

    scheduler.addTask(Task("Complete report", 3, 60));
    scheduler.addTask(Task("Debug critical issue", 5, 30));
    scheduler.addTask(Task("Refactor code", 2, 120));
    scheduler.addTask(Task("Security patch", 4, 45));

    std::cout << "Number of tasks: " << scheduler.size() << std::endl;

    while (!scheduler.isEmpty()) {
        Task nextTask = scheduler.removeNextTask();
        std::cout << "Executing: " << nextTask.getName() 
                  << " (Priority: " << nextTask.getPriority() 
                  << ", Execution time: " << nextTask.getExecutionTime() << " minutes)" << std::endl;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Node for adjacency list
typedef struct Node {
    int serverID;
    struct Node* next;
} Node;

// Graph structure
typedef struct Graph {
    int numServers;
    Node** adjList;
} Graph;

// Queue structure for BFS
typedef struct QueueNode {
    int serverID;
    struct QueueNode* next;
} QueueNode;

typedef struct Queue {
    QueueNode* front;
    QueueNode* rear;
} Queue;

// Function prototypes
Graph* createGraph(int numServers);
void addEdge(Graph* graph, int src, int dest);
bool BFS(Graph* graph, int start, int target);
Queue* createQueue();
bool isQueueEmpty(Queue* queue);
void enqueue(Queue* queue, int serverID);
int dequeue(Queue* queue);
void freeGraph(Graph* graph);
void freeQueue(Queue* queue);

int main() {
    FILE* file = fopen("network.txt", "r");
    if (file == NULL) {
        printf("Failed to open the file.\n");
        return 1;
    }

    int numServers, numConnections;
    fscanf(file, "%d %d", &numServers, &numConnections);

    Graph* graph = createGraph(numServers);

    int src, dest;
    for (int i = 0; i < numConnections; i++) {
        fscanf(file, "%d %d", &src, &dest);
        addEdge(graph, src, dest);
    }

    int startServer, targetServer;
    fscanf(file, "%d %d", &startServer, &targetServer);

    fclose(file);

    if (BFS(graph, startServer, targetServer)) {
        printf("Path exists from server %d to server %d.\n", startServer, targetServer);
    } else {
        printf("No path exists from server %d to server %d.\n", startServer, targetServer);
    }

    freeGraph(graph);
    return 0;
}

Graph* createGraph(int numServers) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->numServers = numServers;
    graph->adjList = (Node**)malloc(numServers * sizeof(Node*));

    for (int i = 0; i < numServers; i++) {
        graph->adjList[i] = NULL;
    }

    return graph;
}

void addEdge(Graph* graph, int src, int dest) {
    // Add edge from src to dest
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->serverID = dest;
    newNode->next = graph->adjList[src];
    graph->adjList[src] = newNode;

    // Add edge from dest to src (undirected graph)
    newNode = (Node*)malloc(sizeof(Node));
    newNode->serverID = src;
    newNode->next = graph->adjList[dest];
    graph->adjList[dest] = newNode;
}

Queue* createQueue() {
    Queue* queue = (Queue*)malloc(sizeof(Queue));
    queue->front = queue->rear = NULL;
    return queue;
}

bool isQueueEmpty(Queue* queue) {
    return queue->front == NULL;
}

void enqueue(Queue* queue, int serverID) {
    QueueNode* newNode = (QueueNode*)malloc(sizeof(QueueNode));
    newNode->serverID = serverID;
    newNode->next = NULL;

    if (isQueueEmpty(queue)) {
        queue->front = queue->rear = newNode;
        return;
    }

    queue->rear->next = newNode;
    queue->rear = newNode;
}

int dequeue(Queue* queue) {
    if (isQueueEmpty(queue)) {
        return -1;
    }

    QueueNode* temp = queue->front;
    int serverID = temp->serverID;

    queue->front = queue->front->next;

    if (queue->front == NULL) {
        queue->rear = NULL;
    }

    free(temp);
    return serverID;
}

bool BFS(Graph* graph, int start, int target) {
    bool* visited = (bool*)malloc(graph->numServers * sizeof(bool));
    for (int i = 0; i < graph->numServers; i++) {
        visited[i] = false;
    }

    Queue* queue = createQueue();
    visited[start] = true;
    enqueue(queue, start);

    while (!isQueueEmpty(queue)) {
        int current = dequeue(queue);

        if (current == target) {
            free(visited);
            freeQueue(queue);
            return true;
        }

        Node* temp = graph->adjList[current];
        while (temp) {
            int adjServer = temp->serverID;
            if (!visited[adjServer]) {
                visited[adjServer] = true;
                enqueue(queue, adjServer);
            }
            temp = temp->next;
        }
    }

    free(visited);
    freeQueue(queue);
    return false;
}

void freeGraph(Graph* graph) {
    for (int i = 0; i < graph->numServers; i++) {
        Node* current = graph->adjList[i];
        while (current) {
            Node* temp = current;
            current = current->next;
            free(temp);
        }
    }
    free(graph->adjList);
    free(graph);
}

void freeQueue(Queue* queue) {
    while (!isQueueEmpty(queue)) {
        dequeue(queue);
    }
    free(queue);
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_CHAR 256
#define MAX_TEXT_LENGTH 1000
#define MAX_PATTERN_LENGTH 100

typedef struct SuffixTreeNode {
    struct SuffixTreeNode *children[MAX_CHAR];
    struct SuffixTreeNode *suffixLink;
    int start;
    int *end;
    int suffixIndex;
} Node;

char text[MAX_TEXT_LENGTH];
Node *root = NULL;
Node *lastNewNode = NULL;
Node *activeNode = NULL;
int activeEdge = -1;
int activeLength = 0;
int remainingSuffixCount = 0;
int leafEnd = -1;
int *rootEnd = NULL;
int *splitEnd = NULL;
int size = 0;

Node *newNode(int start, int *end) {
    Node *node = (Node*)malloc(sizeof(Node));
    for (int i = 0; i < MAX_CHAR; i++)
        node->children[i] = NULL;

    node->suffixLink = root;
    node->start = start;
    node->end = end;
    node->suffixIndex = -1;
    return node;
}

int edgeLength(Node *n) {
    return *(n->end) - (n->start) + 1;
}

int walkDown(Node *currNode) {
    if (activeLength >= edgeLength(currNode)) {
        activeEdge += edgeLength(currNode);
        activeLength -= edgeLength(currNode);
        activeNode = currNode;
        return 1;
    }
    return 0;
}

void extendSuffixTree(int pos) {
    leafEnd = pos;
    remainingSuffixCount++;
    lastNewNode = NULL;

    while (remainingSuffixCount > 0) {
        if (activeLength == 0)
            activeEdge = pos;

        if (activeNode->children[text[activeEdge]] == NULL) {
            activeNode->children[text[activeEdge]] = newNode(pos, &leafEnd);
            if (lastNewNode != NULL) {
                lastNewNode->suffixLink = activeNode;
                lastNewNode = NULL;
            }
        } else {
            Node *next = activeNode->children[text[activeEdge]];
            if (walkDown(next))
                continue;

            if (text[next->start + activeLength] == text[pos]) {
                if (lastNewNode != NULL && activeNode != root) {
                    lastNewNode->suffixLink = activeNode;
                    lastNewNode = NULL;
                }
                activeLength++;
                break;
            }

            splitEnd = (int*)malloc(sizeof(int));
            *splitEnd = next->start + activeLength - 1;
            Node *split = newNode(next->start, splitEnd);
            activeNode->children[text[activeEdge]] = split;
            split->children[text[pos]] = newNode(pos, &leafEnd);
            next->start += activeLength;
            split->children[text[next->start]] = next;

            if (lastNewNode != NULL)
                lastNewNode->suffixLink = split;
            lastNewNode = split;
        }

        remainingSuffixCount--;
        if (activeNode == root && activeLength > 0) {
            activeLength--;
            activeEdge = pos - remainingSuffixCount + 1;
        } else if (activeNode != root) {
            activeNode = activeNode->suffixLink;
        }
    }
}

void buildSuffixTree() {
    size = strlen(text);
    rootEnd = (int*)malloc(sizeof(int));
    *rootEnd = -1;

    root = newNode(-1, rootEnd);
    activeNode = root;

    for (int i = 0; i < size; i++)
        extendSuffixTree(i);

    int *labelHeight = (int*)malloc(sizeof(int) * size);
    setSuffixIndexByDFS(root, 0, labelHeight);
}

void setSuffixIndexByDFS(Node *n, int labelHeight, int *labelHeightArray) {
    if (n == NULL)
        return;

    int leaf = 1;
    for (int i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            leaf = 0;
            setSuffixIndexByDFS(n->children[i], labelHeight + edgeLength(n->children[i]), labelHeightArray);
        }
    }

    if (leaf == 1) {
        n->suffixIndex = size - labelHeight;
    }
}

void freeSuffixTreeByPostOrder(Node *n) {
    if (n == NULL)
        return;

    for (int i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            freeSuffixTreeByPostOrder(n->children[i]);
        }
    }

    if (n->suffixIndex == -1)
        free(n->end);
    free(n);
}

void searchSubstring(char *pattern) {
    int patternLength = strlen(pattern);
    int found = 0;

    Node *currentNode = root;
    int i = 0;

    while (i < patternLength) {
        int currentChar = pattern[i];
        if (currentNode->children[currentChar] == NULL)
            break;

        Node *child = currentNode->children[currentChar];
        int j;

        for (j = 0; j < edgeLength(child) && i < patternLength; j++, i++) {
            if (text[child->start + j] != pattern[i])
                break;
        }

        if (j != edgeLength(child) || i == patternLength)
            break;

        currentNode = child;
    }

    if (i == patternLength) {
        printAllOccurrences(currentNode, pattern);
        found = 1;
    }

    if (!found)
        printf("Pattern '%s' not found in the text\n", pattern);
}

void printAllOccurrences(Node *n, char *pattern) {
    if (n == NULL)
        return;

    if (n->suffixIndex >= 0) {
        printf("Pattern '%s' found at index %d\n", pattern, n->suffixIndex);
        return;
    }

    for (int i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            printAllOccurrences(n->children[i], pattern);
        }
    }
}

