function bubbleSortGrades(grades) {
  const sortedGrades = [...grades];
  let swapCount = 0;

  for (let i = 0; i < sortedGrades.length - 1; i++) {
    for (let j = 0; j < sortedGrades.length - i - 1; j++) {
      if (sortedGrades[j] > sortedGrades[j + 1]) {
        // Swap elements
        const temp = sortedGrades[j];
        sortedGrades[j] = sortedGrades[j + 1];
        sortedGrades[j + 1] = temp;
        swapCount++;
      }
    }
  }

  return {
    sortedGrades: sortedGrades,
    swapCount: swapCount
  };
}

#include <iostream>
#include <string>
#include <queue>
