#include <vector>

using namespace std;

// Node structure for Huffman Tree
struct Node {
    char data;
    unsigned frequency;
    Node *left, *right;

    Node(char data, unsigned frequency) {
        this->data = data;
        this->frequency = frequency;
        left = right = nullptr;
    }
};

// Comparison class for priority queue
struct Compare {
    bool operator()(Node* left, Node* right) {
        return left->frequency > right->frequency;
    }
};

// Function to build Huffman Tree
Node* buildHuffmanTree(string text) {
    // Count frequency of each character
    unordered_map<char, unsigned> freq;
    for (char c : text) {
        freq[c]++;
    }

    // Create a min heap (priority queue)
    priority_queue<Node*, vector<Node*>, Compare> minHeap;

    // Create a leaf node for each character and add it to the min heap
    for (auto pair : freq) {
        minHeap.push(new Node(pair.first, pair.second));
    }

    // Until there is more than one node in the queue
    while (minHeap.size() > 1) {
        // Extract the two nodes with the lowest frequency
        Node* left = minHeap.top();
        minHeap.pop();

        Node* right = minHeap.top();
        minHeap.pop();

        // Create a new internal node with these two nodes as children
        // and with frequency equal to the sum of the two nodes' frequencies
        Node* internalNode = new Node('$', left->frequency + right->frequency);
        internalNode->left = left;
        internalNode->right = right;

        minHeap.push(internalNode);
    }

    // The remaining node is the root node and the tree is complete
    return minHeap.top();
}

// Function to store the codes in a map
void storeCodes(Node* root, string code, unordered_map<char, string>& codes) {
    if (!root) {
        return;
    }

    // If this is a leaf node, store the code
    if (!root->left && !root->right) {
        codes[root->data] = code;
    }

    // Traverse left with code + "0"
    storeCodes(root->left, code + "0", codes);

    // Traverse right with code + "1"
    storeCodes(root->right, code + "1", codes);
}

// Function to encode the input string
string encodeString(string text, unordered_map<char, string>& codes) {
    string encodedString = "";
    for (char c : text) {
        encodedString += codes[c];
    }
    return encodedString;
}

// Main Huffman coding function
void huffmanCoding(string text) {
    // Build Huffman Tree
    Node* root = buildHuffmanTree(text);

    // If the text has only one character
    if (!root->left && !root->right) {
        cout << "Encoded string: 0" << endl;
        cout << "Character mapping:" << endl;
        cout << root->data << " -> 0" << endl;
        return;
    }

    // Store the codes in a map
    unordered_map<char, string> codes;
    storeCodes(root, "", codes);

    // Encode the input string
    string encodedString = encodeString(text, codes);

    // Output the encoded string
    cout << "Encoded string: " << encodedString << endl;

    // Output the character mapping
    cout << "Character mapping:" << endl;
    for (auto pair : codes) {
        cout << pair.first << " -> " << pair.second << endl;
    }
}

int main() {
    string text;
    cout << "Enter the text to compress: ";
    getline(cin, text);

    huffmanCoding(text);

    return 0;
}

