fn solve_n_queens(board: &mut Vec<i32>, row: usize, solutions: &mut Vec<Vec<i32>>) {
    if row == 8 {
        solutions.push(board.clone());
        return;
    }

    for col in 0..8 {
        if is_safe(board, row, col) {
            board[row] = col as i32;
            solve_n_queens(board, row + 1, solutions);
        }
    }
}

fn is_safe(board: &Vec<i32>, row: usize, col: i32) -> bool {
    for i in 0..row {
        let prev_col = board[i];

        // Check if queens are in the same column
        if prev_col == col {
            return false;
        }

        // Check if queens are in the same diagonal
        let col_diff = (prev_col - col).abs();
        let row_diff = (i as i32 - row as i32).abs();

        if col_diff == row_diff {
            return false;
        }
    }
    true
}

fn print_solution(board: &Vec<i32>) {
    for row in 0..8 {
        for col in 0..8 {
            if board[row] == col as i32 {
                print!("Q ");
            } else {
                print!(". ");
            }
        }
        println!();
    }
}

public class Palindrome {
    public static boolean isPalindrome(String str) {
        if (str == null) {
            return false;
        }

        // Normalize the string by removing non-alphanumeric characters and converting to lowercase
        String normalized = str.replaceAll("[^a-zA-Z0-9]", "").toLowerCase();

        // Base case for empty string or single character
        if (normalized.length() <= 1) {
            return true;
        }

        // Recursive approach to check if the string is a palindrome
        return isPalindromeRecursive(normalized, 0, normalized.length() - 1);
    }

    private static boolean isPalindromeRecursive(String str, int left, int right) {
        // Base case: if we've checked all characters or reached the middle
        if (left >= right) {
            return true;
        }

        // If characters at both ends don't match, it's not a palindrome
        if (str.charAt(left) != str.charAt(right)) {
            return false;
        }

        // Recursive call to check the next pair of characters
        return isPalindromeRecursive(str, left + 1, right - 1);
    }

    public static void main(String[] args) {
        String testString = "A man, a plan, a canal: Panama";
        System.out.println(isPalindrome(testString)); // Should print: true
    }
}

import java.util.*;

public class PerfectHash {
    private final UserData[] userDataTable;
    private final int[] g;
    private final int[] h;
    private final int m;
    private final int r;

    public PerfectHash(List<String> usernames) {
        int n = usernames.size();
        m = nextPrime(n);
        r = nextPrime(m);

        // First-level hash: h(x) = (x mod r)
        int[] buckets = new int[r];
        for (String username : usernames) {
            int hashValue = firstLevelHash(username);
            buckets[hashValue]++;
        }

        // Calculate table sizes for second level
        int totalSize = 0;
        for (int i = 0; i < r; i++) {
            int bucketSize = buckets[i];
            if (bucketSize > 0) {
                totalSize += bucketSize * bucketSize;
            }
        }

        // Initialize second-level tables
        userDataTable = new UserData[totalSize];
        g = new int[r];
        h = new int[r];

        // Set up displacement values for each bucket
        int displacement = 0;
        for (int i = 0; i < r; i++) {
            g[i] = displacement;
            int bucketSize = buckets[i];
            if (bucketSize > 0) {
                displacement += bucketSize * bucketSize;
            }
        }

        // Find collision-free hash functions for each bucket
        String[][] bucketItems = new String[r][];
        for (int i = 0; i < r; i++) {
            bucketItems[i] = new String[buckets[i]];
        }

        int[] bucketCounts = new int[r];
        for (String username : usernames) {
            int hashValue = firstLevelHash(username);
            bucketItems[hashValue][bucketCounts[hashValue]++] = username;
        }

        // Compute perfect hash function for each bucket
        for (int i = 0; i < r; i++) {
            if (buckets[i] > 0) {
                findPerfectSecondHash(i, bucketItems[i]);
            }
        }

        // Store user data
        for (String username : usernames) {
            int index = getIndex(username);
            userDataTable[index] = new UserData(username, 
                "User " + username.hashCode(), 
                username.toLowerCase() + "@example.com");
        }
    }

    private void findPerfectSecondHash(int bucketIndex, String[] items) {
        int bucketSize = items.length;
        if (bucketSize <= 1) {
            h[bucketIndex] = 1; // Any value works for single item
            return;
        }

        boolean[] occupied = new boolean[bucketSize * bucketSize];
        boolean collision;

        do {
            collision = false;
            h[bucketIndex] = 1 + (int)(Math.random() * (m - 1));
            Arrays.fill(occupied, false);

            for (String item : items) {
                int hash2 = secondLevelHash(item, h[bucketIndex]);
                int position = hash2 % (bucketSize * bucketSize);

                if (occupied[position]) {
                    collision = true;
                    break;
                }
                occupied[position] = true;
            }
        } while (collision);
    }

    private int firstLevelHash(String s) {
        int hash = 0;
        for (char c : s.toCharArray()) {
            hash = (hash * 31 + c) % r;
        }
        return Math.abs(hash);
    }

    private int secondLevelHash(String s, int a) {
        int hash = 0;
        for (char c : s.toCharArray()) {
            hash = (hash * a + c) % m;
        }
        return Math.abs(hash);
    }

    public int getIndex(String username) {
        int bucket = firstLevelHash(username);
        int hash2 = secondLevelHash(username, h[bucket]);
        int bucketSize = (int)Math.sqrt((userDataTable.length > 0) ? 
            (g[bucket+1 < r ? bucket+1 : bucket] - g[bucket]) : 0);
        return g[bucket] + (hash2 % (bucketSize * bucketSize));
    }

    public UserData getUserData(String username) {
        int index = getIndex(username);
        UserData data = userDataTable[index];
        if (data != null && data.getUsername().equals(username)) {
            return data;
        }
        return null;
    }

    private int nextPrime(int n) {
        if (n <= 2) return 2;
        int prime = (n % 2 == 0) ? n + 1 : n;
        while (!isPrime(prime)) prime += 2;
        return prime;
    }

    private boolean isPrime(int n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (int i = 5; i * i <= n; i += 6) {
            if (n % i == 0 || n % (i + 2) == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) {
        List<String> usernames = Arrays.asList("john_doe", "jane_smith", "bob_jackson", 
            "alice_wonder", "mike_tyson", "sarah_connor");

        PerfectHash perfectHash = new PerfectHash(usernames);

        for (String username : usernames) {
            System.out.println("Index for " + username + ": " + perfectHash.getIndex(username));
            UserData user = perfectHash.getUserData(username);
            System.out.println("User found: " + user);
        }

        UserData nonExistentUser = perfectHash.getUserData("unknown_user");
        System.out.println("Unknown user result: " + (nonExistentUser == null ? "Not found" : nonExistentUser));
    }
}

