#include <iostream>
#include <vector>
#include <algorithm>

struct Task {
    std::string name;
    int duration;
    int priority;
};

std::vector<Task> optimizeSchedule(const std::vector<Task>& tasks, int timeLimit) {
    int n = tasks.size();

    // Create DP table: dp[i][t] = max priority for first i tasks with t time
    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(timeLimit + 1, 0));
    std::vector<std::vector<bool>> selected(n + 1, std::vector<bool>(timeLimit + 1, false));

    // Fill the DP table
    for (int i = 1; i <= n; i++) {
        for (int t = 0; t <= timeLimit; t++) {
            // Don't take current task
            dp[i][t] = dp[i-1][t];

            // Take current task if we have enough time
            if (t >= tasks[i-1].duration && dp[i-1][t - tasks[i-1].duration] + tasks[i-1].priority > dp[i][t]) {
                dp[i][t] = dp[i-1][t - tasks[i-1].duration] + tasks[i-1].priority;
                selected[i][t] = true;
            }
        }
    }

    // Reconstruct the selected tasks
    std::vector<Task> schedule;
    int remainingTime = timeLimit;

    for (int i = n; i > 0; i--) {
        if (selected[i][remainingTime]) {
            schedule.push_back(tasks[i-1]);
            remainingTime -= tasks[i-1].duration;
        }
    }

    std::reverse(schedule.begin(), schedule.end());
    return schedule;
}

int main() {
    const int TIME_LIMIT = 8 * 60; // 8 hours in minutes
    std::vector<Task> tasks;

    // Sample tasks
    tasks.push_back({"Implement login feature", 120, 8});
    tasks.push_back({"Fix homepage bug", 45, 9});
    tasks.push_back({"Design database schema", 180, 7});
    tasks.push_back({"Write unit tests", 90, 6});
    tasks.push_back({"Documentation", 150, 4});
    tasks.push_back({"Code review", 60, 5});
    tasks.push_back({"Deploy to staging", 30, 7});
    tasks.push_back({"Client meeting", 60, 10});
    tasks.push_back({"Refactor legacy code", 210, 3});
    tasks.push_back({"Security audit", 120, 8});

    std::vector<Task> optimalSchedule = optimizeSchedule(tasks, TIME_LIMIT);

    // Display the optimal schedule
    std::cout << "Optimal Schedule (8-hour workday):\n";
    std::cout << "---------------------------------\n";

    int totalDuration = 0;
    int totalPriority = 0;

    for (const Task& task : optimalSchedule) {
        std::cout << "Task: " << task.name << "\n";
        std::cout << "Duration: " << task.duration << " minutes\n";
        std::cout << "Priority: " << task.priority << "\n";
        std::cout << "---------------------------------\n";

        totalDuration += task.duration;
        totalPriority += task.priority;
    }

    std::cout << "Total Duration: " << totalDuration << " minutes\n";
    std::cout << "Total Priority Score: " << totalPriority << "\n";

    return 0;
}

def fnv1a_hash(data, hash_size=32):
    if hash_size == 32:
        # 32-bit FNV-1a parameters
        FNV_PRIME = 16777619
        FNV_OFFSET_BASIS = 2166136261
    elif hash_size == 64:
        # 64-bit FNV-1a parameters
        FNV_PRIME = 1099511628211
        FNV_OFFSET_BASIS = 14695981039346656037
    else:
        raise ValueError("Hash size must be 32 or 64 bits")

    # Initialize hash with offset basis
    hash_value = FNV_OFFSET_BASIS

    # For each byte in the data
    for byte in data.encode('utf-8'):
        # XOR hash with the current byte
        hash_value ^= byte
        # Multiply by the FNV prime
        hash_value = (hash_value * FNV_PRIME) & ((1 << hash_size) - 1)

    return hash_value

def hash_strings_from_file(input_file, output_file, hash_size=32):
    try:
        with open(input_file, 'r', encoding='utf-8') as infile:
            strings = infile.read().splitlines()

        with open(output_file, 'w', encoding='utf-8') as outfile:
            outfile.write(f"{'String':<30} | {'Length':<10} | {'FNV-1a Hash':<20}\n")
            outfile.write("-" * 65 + "\n")

            for s in strings:
                hash_value = fnv1a_hash(s, hash_size)
                outfile.write(f"{s[:30]:<30} | {len(s):<10} | {hash_value:<20}\n")

        print(f"Hashing completed. Results written to {output_file}")

    except FileNotFoundError:
        print(f"Error: Input file {input_file} not found.")
    except Exception as e:
        print(f"An error occurred: {e}")

