use std::collections::{BinaryHeap, HashMap, HashSet};
use std::cmp::Ordering;
use std::io::{self, BufRead};

// Edge representation with source, destination and weight
#[derive(Debug, Clone)]
struct Edge {
    src: usize,
    dst: usize,
    weight: i32,
}

// Custom wrapper for BinaryHeap to use as a min-heap
#[derive(Debug, Eq, PartialEq)]
struct MinHeapNode {
    vertex: usize,
    weight: i32,
}

impl Ord for MinHeapNode {
    fn cmp(&self, other: &Self) -> Ordering {
        // Reverse ordering for min-heap
        other.weight.cmp(&self.weight)
    }
}

impl PartialOrd for MinHeapNode {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Graph representation
struct Graph {
    vertices: usize,
    adj_list: HashMap<usize, Vec<(usize, i32)>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            vertices: 0,
            adj_list: HashMap::new(),
        }
    }

    fn add_edge(&mut self, src: usize, dst: usize, weight: i32) {
        self.adj_list.entry(src).or_insert(Vec::new()).push((dst, weight));
        self.adj_list.entry(dst).or_insert(Vec::new()).push((src, weight));
        self.vertices = self.vertices.max(src + 1).max(dst + 1);
    }

    fn prim_mst(&self) -> Vec<Edge> {
        let mut result = Vec::new();

        // Return empty result if graph is empty
        if self.vertices == 0 {
            return result;
        }

        // Priority queue for selecting minimum weight edges
        let mut min_heap = BinaryHeap::new();

        // Track vertices included in MST
        let mut mst_set = HashSet::new();

        // Track the key values used to pick minimum weight edge
        let mut key = vec![i32::MAX; self.vertices];

        // Track parent of each vertex in MST
        let mut parent = vec![usize::MAX; self.vertices];

        // Start with vertex 0
        let start_vertex = 0;
        key[start_vertex] = 0;
        min_heap.push(MinHeapNode { vertex: start_vertex, weight: 0 });

        // Process until all vertices are included in MST
        while mst_set.len() < self.vertices && !min_heap.is_empty() {
            // Extract minimum key vertex
            let u = min_heap.pop().unwrap().vertex;

            // Skip if already in MST
            if mst_set.contains(&u) {
                continue;
            }

            // Add to MST
            mst_set.insert(u);

            // Add edge to result except for the start vertex
            if u != start_vertex {
                result.push(Edge {
                    src: parent[u],
                    dst: u,
                    weight: key[u],
                });
            }

            // Update key and parent for adjacent vertices
            if let Some(adj) = self.adj_list.get(&u) {
                for &(v, weight) in adj {
                    if !mst_set.contains(&v) && weight < key[v] {
                        parent[v] = u;
                        key[v] = weight;
                        min_heap.push(MinHeapNode { vertex: v, weight });
                    }
                }
            }
        }

        result
    }
}

fn main() {
    let mut graph = Graph::new();

    println!("Enter edges as 'source destination weight', one edge per line.");
    println!("Enter a blank line to finish input.");

    let stdin = io::stdin();
    let mut lines = stdin.lock().lines();

    while let Some(Ok(line)) = lines.next() {
        if line.trim().is_empty() {
            break;
        }

        let parts: Vec<&str> = line.trim().split_whitespace().collect();
        if parts.len() == 3 {
            if let (Ok(src), Ok(dst), Ok(weight)) = (
                parts[0].parse::<usize>(),
                parts[1].parse::<usize>(),
                parts[2].parse::<i32>(),
            ) {
                graph.add_edge(src, dst, weight);
            } else {
                println!("Invalid input format. Expected 'source destination weight'.");
            }
        } else {
            println!("Invalid input format. Expected 'source destination weight'.");
        }
    }

    let mst = graph.prim_mst();

    println!("\nMinimum Spanning Tree Edges:");
    let mut total_weight = 0;
    for edge in &mst {
        println!("{} -- {} : {}", edge.src, edge.dst, edge.weight);
        total_weight += edge.weight;
    }

    println!("\nTotal MST Weight: {}", total_weight);
}

