struct Edge {
    int src, dest, weight;
};

struct Graph {
    int V, E;
    struct Edge* edge;
};

struct Graph* createGraph(int V, int E) {
    struct Graph* graph = (struct Graph*) malloc(sizeof(struct Graph));
    graph->V = V;
    graph->E = E;
    graph->edge = (struct Edge*) malloc(E * sizeof(struct Edge));
    return graph;
}

void bellmanFord(struct Graph* graph, int src) {
    int V = graph->V;
    int E = graph->E;
    int dist[V];

    // Initialize distances
    for (int i = 0; i < V; i++)
        dist[i] = INT_MAX;
    dist[src] = 0;

    // Relax all edges V-1 times
    for (int i = 1; i < V; i++) {
        for (int j = 0; j < E; j++) {
            int u = graph->edge[j].src;
            int v = graph->edge[j].dest;
            int weight = graph->edge[j].weight;
            if (dist[u] != INT_MAX && dist[u] + weight < dist[v])
                dist[v] = dist[u] + weight;
        }
    }

    // Check for negative-weight cycles
    for (int i = 0; i < E; i++) {
        int u = graph->edge[i].src;
        int v = graph->edge[i].dest;
        int weight = graph->edge[i].weight;
        if (dist[u] != INT_MAX && dist[u] + weight < dist[v]) {
            printf("Graph contains negative weight cycle\n");
            return;
        }
    }

    // Print shortest distances
    printf("Vertex   Distance from Source\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t %d\n", i, dist[i]);
}

int main() {
    int V, E, src;

    printf("Enter number of vertices: ");
    scanf("%d", &V);
    printf("Enter number of edges: ");
    scanf("%d", &E);

    struct Graph* graph = createGraph(V, E);

    printf("Enter edge details (src dest weight):\n");
    for (int i = 0; i < E; i++) {
        scanf("%d %d %d", &graph->edge[i].src, &graph->edge[i].dest, &graph->edge[i].weight);
    }

    printf("Enter source vertex: ");
    scanf("%d", &src);

    bellmanFord(graph, src);

    free(graph->edge);
    free(graph);

    return 0;
}

use std::io::{self, BufRead};
use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct Edge {
    from: usize,
    to: usize,
    weight: i32,
}

struct DisjointSet {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DisjointSet {
    fn new(size: usize) -> Self {
        DisjointSet {
            parent: (0..size).collect(),
            rank: vec![0; size],
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let root_x = self.find(x);
        let root_y = self.find(y);

        if root_x == root_y {
            return false;
        }

        if self.rank[root_x] < self.rank[root_y] {
            self.parent[root_x] = root_y;
        } else if self.rank[root_x] > self.rank[root_y] {
            self.parent[root_y] = root_x;
        } else {
            self.parent[root_y] = root_x;
            self.rank[root_x] += 1;
        }
        true
    }
}

fn kruskal_mst(edges: &[Edge], vertices: usize) -> Vec<Edge> {
    let mut result = Vec::new();
    let mut disjoint_set = DisjointSet::new(vertices);

    // Sort edges by weight
    let mut sorted_edges = BinaryHeap::new();
    for edge in edges {
        sorted_edges.push(Reverse((edge.weight, edge.from, edge.to)));
    }

    while !sorted_edges.is_empty() && result.len() < vertices - 1 {
        let Reverse((weight, from, to)) = sorted_edges.pop().unwrap();

        if disjoint_set.union(from, to) {
            result.push(Edge { from, to, weight });
        }
    }

    result
}

fn main() {
    let stdin = io::stdin();
    let mut lines = stdin.lock().lines();

    // First line: Number of vertices and edges
    let first_line = lines.next().unwrap().unwrap();
    let parts: Vec<usize> = first_line
        .split_whitespace()
        .map(|s| s.parse().unwrap())
        .collect();

    let vertices = parts[0];
    let edge_count = parts[1];

    // Read edges
    let mut edges = Vec::new();
    for _ in 0..edge_count {
        let line = lines.next().unwrap().unwrap();
        let parts: Vec<i32> = line
            .split_whitespace()
            .map(|s| s.parse().unwrap())
            .collect();

        edges.push(Edge {
            from: parts[0] as usize,
            to: parts[1] as usize,
            weight: parts[2],
        });
    }

    // Find MST
    let mst_edges = kruskal_mst(&edges, vertices);

    // Output MST edges
    println!("Minimum Spanning Tree Edges:");
    let mut total_weight = 0;
    for edge in mst_edges {
        println!("{} -- {} (weight: {})", edge.from, edge.to, edge.weight);
        total_weight += edge.weight;
    }
    println!("Total MST weight: {}", total_weight);
}

