fn main() {
    // Example input
    let tasks = vec![
        Task { id: 1, requirements: vec![1, 3, 5] },
        Task { id: 2, requirements: vec![2, 3] },
        Task { id: 3, requirements: vec![1, 2, 4] },
        Task { id: 4, requirements: vec![4, 5] },
        Task { id: 5, requirements: vec![1, 5] },
    ];
    let max_requirements = 3;

    let result = max_completable_tasks(&tasks, max_requirements);
    println!("Maximum number of completable tasks: {}", result.len());
    println!("Tasks: {:?}", result);
