#[derive(Debug, Clone)]
struct Task {
    id: usize,
    requirements: Vec<usize>,
}

fn max_completable_tasks(tasks: &[Task], max_requirements: usize) -> Vec<usize> {
    // Create bit representation for each task's requirements
    let task_bits: Vec<(usize, u64)> = tasks.iter()
        .map(|task| {
            let bit_mask = task.requirements.iter()
                .fold(0u64, |mask, &req| mask | (1u64 << (req - 1)));
            (task.id, bit_mask)
        })
        .collect();

    // Store the best task combination
    let mut max_tasks = Vec::new();

    // Generate all possible requirement combinations within the limit
    let max_req_id = tasks.iter()
        .flat_map(|task| &task.requirements)
        .max()
        .cloned()
        .unwrap_or(0);

    // Use bit masking to represent the requirements
    // We'll explore all subsets up to 2^max_req_id
    let req_combinations_limit = 1u64 << max_req_id;

    for req_combination in 0..req_combinations_limit {
        // Skip if the combination has more than max_requirements bits set
        if req_combination.count_ones() as usize > max_requirements {
            continue;
        }

        // Find all tasks that can be completed with this requirement combination
        let mut compatible_tasks = Vec::new();

        for &(task_id, task_req_bits) in &task_bits {
            // A task is compatible if all its requirements are included in our combination
            if task_req_bits & req_combination == task_req_bits {
                compatible_tasks.push(task_id);
            }
        }

        // Update the best solution if we found a better one
        if compatible_tasks.len() > max_tasks.len() {
            max_tasks = compatible_tasks;
        }
    }

    max_tasks
}
