function findLowestCommonAncestor(root, p, q) {
  if (!root) return null;

  // Step 1: Build the parent pointers and calculate depth for each node
  const parents = new Map();
  const depths = new Map();

  function dfs(node, parent, depth) {
    if (!node) return;

    parents.set(node, parent);
    depths.set(node, depth);

    dfs(node.left, node, depth + 1);
    dfs(node.right, node, depth + 1);
  }

  dfs(root, null, 0);

  // Check if both nodes exist in the tree
  if (!parents.has(p) || !parents.has(q)) {
    return null;
  }

  // Step 2: Ensure p is deeper than q (or swap them)
  if (depths.get(p) < depths.get(q)) {
    [p, q] = [q, p];
  }

  // Step 3: Binary Lifting - Bring p to the same level as q
  let diff = depths.get(p) - depths.get(q);
  while (diff > 0) {
    p = parents.get(p);
    diff--;
  }

  // Step 4: Move both nodes up until they meet
  while (p !== q) {
    p = parents.get(p);
    q = parents.get(q);
  }

  return p;
}

// Optimized version with binary lifting preprocessing
function findLCAWithBinaryLifting(root, p, q) {
  if (!root) return null;

  const nodes = [];
  const depths = new Map();
  const nodeToIndex = new Map();

  // DFS to collect nodes and their depths
  function dfs(node, depth) {
    if (!node) return;

    nodeToIndex.set(node, nodes.length);
    nodes.push(node);
    depths.set(node, depth);

    dfs(node.left, depth + 1);
    dfs(node.right, depth + 1);
  }

  dfs(root, 0);

  // Check if both nodes exist in the tree
  if (!nodeToIndex.has(p) || !nodeToIndex.has(q)) {
    return null;
  }

  const n = nodes.length;
  const logN = Math.floor(Math.log2(n)) + 1;

  // Binary lifting parent array: up[i][j] is the 2^j-th ancestor of node i
  const up = Array(n).fill().map(() => Array(logN).fill(null));

  // Fill the first ancestors (2^0 = 1 step up)
  for (let i = 0; i < n; i++) {
    const node = nodes[i];
    if (node === root) {
      up[i][0] = null;
    } else {
      if (node === node.parent?.left || node === node.parent?.right) {
        up[i][0] = nodeToIndex.get(node.parent);
      } else {
        // Find parent through our traversal
        const parent = nodes.find(n => n.left === node || n.right === node);
        up[i][0] = parent ? nodeToIndex.get(parent) : null;
      }
    }
  }

  // Fill the binary lifting table
  for (let j = 1; j < logN; j++) {
    for (let i = 0; i < n; i++) {
      if (up[i][j - 1] !== null) {
        up[i][j] = up[up[i][j - 1]][j - 1];
      }
    }
  }

  const pIdx = nodeToIndex.get(p);
  const qIdx = nodeToIndex.get(q);

  // Ensure p is deeper than q
  let a = depths.get(p) >= depths.get(q) ? pIdx : qIdx;
  let b = depths.get(p) >= depths.get(q) ? qIdx : pIdx;

  // Bring the deeper node to the same level
  let diff = depths.get(nodes[a]) - depths.get(nodes[b]);

  for (let j = logN - 1; j >= 0; j--) {
    if (diff & (1 << j)) {
      a = up[a][j];
    }
  }

  if (a === b) return nodes[a];

  // Binary lift both nodes until just before their LCA
  for (let j = logN - 1; j >= 0; j--) {
    if (up[a][j] !== up[b][j]) {
      a = up[a][j];
      b = up[b][j];
    }
  }

  return nodes[up[a][0]];
}

