struct DisjointSet {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DisjointSet {
    fn new(size: usize) -> Self {
        let mut parent = Vec::with_capacity(size);
        let rank = vec![0; size];

        for i in 0..size {
            parent.push(i);
        }

        DisjointSet { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let root_x = self.find(x);
        let root_y = self.find(y);

        if root_x == root_y {
            return;
        }

        if self.rank[root_x] < self.rank[root_y] {
            self.parent[root_x] = root_y;
        } else if self.rank[root_x] > self.rank[root_y] {
            self.parent[root_y] = root_x;
        } else {
            self.parent[root_y] = root_x;
            self.rank[root_x] += 1;
        }
    }

    fn connected(&mut self, x: usize, y: usize) -> bool {
        self.find(x) == self.find(y)
    }
}

fn main() {
    let size = 10;
    let mut ds = DisjointSet::new(size);

    // Example operations
    ds.union(0, 1);
    ds.union(2, 3);
    ds.union(4, 5);
    ds.union(6, 7);
    ds.union(0, 2);
    ds.union(4, 6);

    println!("Are 1 and 3 connected? {}", ds.connected(1, 3));
    println!("Are 5 and 7 connected? {}", ds.connected(5, 7));
    println!("Are 3 and 7 connected? {}", ds.connected(3, 7));
}

