class PostfixCalculator {
private:
    std::stack<double> operandStack;

    bool isOperator(const std::string& token) {
        return token == "+" || token == "-" || token == "*" || token == "/";
    }

    double applyOperator(const std::string& op, double a, double b) {
        if (op == "+") return a + b;
        if (op == "-") return a - b;
        if (op == "*") return a * b;
        if (op == "/") {
            if (b == 0) throw std::runtime_error("Division by zero");
            return a / b;
        }
        throw std::runtime_error("Unknown operator: " + op);
    }

public:
    double evaluate(const std::string& expression) {
        std::istringstream iss(expression);
        std::string token;

        while (iss >> token) {
            if (isOperator(token)) {
                if (operandStack.size() < 2) {
                    throw std::runtime_error("Invalid postfix expression: not enough operands");
                }

                double b = operandStack.top();
                operandStack.pop();
                double a = operandStack.top();
                operandStack.pop();

                operandStack.push(applyOperator(token, a, b));
            } else {
                // Try to convert to number
                try {
                    operandStack.push(std::stod(token));
                } catch (const std::exception&) {
                    throw std::runtime_error("Invalid token: " + token);
                }
            }
        }

        if (operandStack.size() != 1) {
            throw std::runtime_error("Invalid postfix expression: too many operands");
        }

        return operandStack.top();
    }

    void reset() {
        while (!operandStack.empty()) {
            operandStack.pop();
        }
    }
};

int main() {
    PostfixCalculator calculator;
    std::string expression;

    std::cout << "Enter a postfix expression (e.g., '3 4 + 5 *'): ";
    std::getline(std::cin, expression);

    try {
        double result = calculator.evaluate(expression);
        std::cout << "Result: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cout << "Error: " << e.what() << std::endl;
    }

    return 0;
}

