use std::f64::INFINITY;

struct TransportNetwork {
    stations: HashMap<String, usize>,
    routes: Vec<(usize, usize, f64)>, // (from_station, to_station, travel_time)
}

impl TransportNetwork {
    fn new() -> Self {
        TransportNetwork {
            stations: HashMap::new(),
            routes: Vec::new(),
        }
    }

    fn add_station(&mut self, name: &str) -> usize {
        let next_id = self.stations.len();
        *self.stations.entry(name.to_string()).or_insert(next_id)
    }

    fn add_route(&mut self, from: &str, to: &str, time: f64) {
        let from_id = self.add_station(from);
        let to_id = self.add_station(to);
        self.routes.push((from_id, to_id, time));
    }

    fn bellman_ford(&self, source: &str) -> Result<HashMap<String, f64>, &'static str> {
        if !self.stations.contains_key(source) {
            return Err("Source station not found in the network");
        }

        let source_id = self.stations[source];
        let station_count = self.stations.len();

        // Initialize distances
        let mut distances: Vec<f64> = vec![f64::INFINITY; station_count];
        distances[source_id] = 0.0;

        // Relax edges repeatedly
        for _ in 0..station_count - 1 {
            for &(from, to, time) in &self.routes {
                if distances[from] != f64::INFINITY && distances[from] + time < distances[to] {
                    distances[to] = distances[from] + time;
                }
            }
        }

        // Check for negative weight cycles
        for &(from, to, time) in &self.routes {
            if distances[from] != f64::INFINITY && distances[from] + time < distances[to] {
                return Err("Negative weight cycle detected");
            }
        }

        // Convert results back to station names
        let mut result = HashMap::new();
        let rev_stations: HashMap<usize, String> = self.stations
            .iter()
            .map(|(name, &id)| (id, name.clone()))
            .collect();

        for (id, &distance) in distances.iter().enumerate() {
            if let Some(station_name) = rev_stations.get(&id) {
                result.insert(station_name.clone(), distance);
            }
        }

        Ok(result)
    }
}

fn main() {
    let mut network = TransportNetwork::new();

    // Add some sample stations and routes
    network.add_route("Central", "North", 10.0);
    network.add_route("Central", "East", 15.0);
    network.add_route("North", "East", 2.0);
    network.add_route("East", "South", 5.0);
    network.add_route("South", "West", 7.0);
    network.add_route("West", "Central", 8.0);
    network.add_route("East", "West", -3.0); // A negative delay (early arrival)

    // Calculate shortest paths from Central station
    match network.bellman_ford("Central") {
        Ok(distances) => {
            println!("Shortest travel times from Central station:");
            for (station, time) in distances {
                if time == f64::INFINITY {
                    println!("{}: Unreachable", station);
                } else {
                    println!("{}: {:.1} minutes", station, time);
                }
            }
        }
        Err(error) => {
            println!("Error: {}", error);
        }
    }
}

class PriorityQueue {
  constructor() {
    this.values = [];
  }

  enqueue(value, priority) {
    this.values.push({ value, priority });
    this.sort();
  }

  dequeue() {
    return this.values.shift();
  }

  sort() {
    this.values.sort((a, b) => a.priority - b.priority);
  }

  isEmpty() {
    return this.values.length === 0;
  }
}

class Graph {
  constructor() {
    this.adjacencyList = {};
  }

  addSubstation(substation) {
    if (!this.adjacencyList[substation]) {
      this.adjacencyList[substation] = [];
    }
  }

  addConnection(substation1, substation2, distance) {
    this.adjacencyList[substation1].push({ node: substation2, weight: distance });
    this.adjacencyList[substation2].push({ node: substation1, weight: distance });
  }

  primMST(start) {
    const MST = [];
    const visited = {};
    const pq = new PriorityQueue();

    // Helper function
    const addToQueue = (substation) => {
      visited[substation] = true;

      this.adjacencyList[substation].forEach(neighbor => {
        if (!visited[neighbor.node]) {
          pq.enqueue({ from: substation, to: neighbor.node }, neighbor.weight);
        }
      });
    };

    // Start with the first substation
    addToQueue(start);

    // Process all edges
    let totalCableLength = 0;

    while (!pq.isEmpty()) {
      const currentEdge = pq.dequeue();
      const { value: { from, to }, priority: distance } = currentEdge;

      if (visited[to]) continue;

      MST.push({ from, to, distance });
      totalCableLength += distance;

      addToQueue(to);
    }

    return { minimumSpanningTree: MST, totalCableLength };
  }
}

// Example usage
function buildPowerGrid(substations, connections) {
  const powerGrid = new Graph();

  // Add all substations
  substations.forEach(substation => {
    powerGrid.addSubstation(substation);
  });

  // Add all possible connections with distances
  connections.forEach(conn => {
    powerGrid.addConnection(conn.from, conn.to, conn.distance);
  });

  // Find the minimum spanning tree starting from the first substation
  const result = powerGrid.primMST(substations[0]);

  return result;
}

