def knapsack_01(weights, values, capacity):
    n = len(weights)
    dp = [[0 for _ in range(capacity + 1)] for _ in range(n + 1)]

    for i in range(1, n + 1):
        for w in range(capacity + 1):
            if weights[i-1] <= w:
                dp[i][w] = max(values[i-1] + dp[i-1][w-weights[i-1]], dp[i-1][w])
            else:
                dp[i][w] = dp[i-1][w]

    return dp[n][capacity]

int lengthOfLIS(std::vector<int>& nums) {
    if (nums.empty()) return 0;

    int n = nums.size();
    std::vector<int> dp(n, 1);

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[i] > nums[j]) {
                dp[i] = std::max(dp[i], dp[j] + 1);
            }
        }
    }

    return *std::max_element(dp.begin(), dp.end());
}

function mergeSort(students) {
  if (students.length <= 1) {
    return students;
  }

  const middle = Math.floor(students.length / 2);
  const left = students.slice(0, middle);
  const right = students.slice(middle);

  return merge(mergeSort(left), mergeSort(right));
}

function merge(left, right) {
  let result = [];
  let leftIndex = 0;
  let rightIndex = 0;

  while (leftIndex < left.length && rightIndex < right.length) {
    if (left[leftIndex].score > right[rightIndex].score) {
      result.push(left[leftIndex]);
      leftIndex++;
    } else if (left[leftIndex].score < right[rightIndex].score) {
      result.push(right[rightIndex]);
      rightIndex++;
    } else {
      // If scores are equal, sort alphabetically by name
      if (left[leftIndex].name <= right[rightIndex].name) {
        result.push(left[leftIndex]);
        leftIndex++;
      } else {
        result.push(right[rightIndex]);
        rightIndex++;
      }
    }
  }

  return result.concat(left.slice(leftIndex)).concat(right.slice(rightIndex));
}

function sortStudentsByScore(students) {
  return mergeSort(students);
}

