function createFitnessPlan(exercises, dailyMaxDuration) {
    // Sort exercises by calorie burn per minute (descending)
    const sortedExercises = [...exercises].sort((a, b) => {
        const ratioA = a.caloriesBurned / a.duration;
        const ratioB = b.caloriesBurned / b.duration;
        return ratioB - ratioA;
    });

    // Weekly plan (7 days)
    const weeklyPlan = Array(7).fill().map(() => ({
        totalDuration: 0,
        totalCalories: 0,
        activities: []
    }));

    // Distribute exercises across the week using greedy approach
    let dayIndex = 0;

    for (const exercise of sortedExercises) {
        let added = false;

        // Try to add the exercise to the current day
        for (let i = 0; i < 7; i++) {
            const currentDayIndex = (dayIndex + i) % 7;
            const day = weeklyPlan[currentDayIndex];

            if (day.totalDuration + exercise.duration <= dailyMaxDuration) {
                day.activities.push({
                    name: exercise.name,
                    duration: exercise.duration,
                    caloriesBurned: exercise.caloriesBurned
                });
                day.totalDuration += exercise.duration;
                day.totalCalories += exercise.caloriesBurned;
                dayIndex = (currentDayIndex + 1) % 7; // Move to next day for next exercise
                added = true;
                break;
            }
        }

        // If we couldn't add it anywhere, just skip it
        if (!added) {
            continue;
        }
    }

    return weeklyPlan;
}

